#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    vector<int> balance(n + 1, 0);

    for (int i = 0; i < m; i++) {
        int a, b, c;
        cin >> a >> b >> c;
        // a owes b the amount c: a loses c, b gains c
        balance[a] -= c;
        balance[b] += c;
    }

    // Collect positive balances (people owed money)
    vector<int> pos;
    for (int i = 1; i <= n; i++) {
        if (balance[i] > 0) pos.push_back(balance[i]);
    }

    // The problem reduces to: we have some positive values (amounts people are owed)
    // and negative values (debts). We want to minimize sum of debts = sum of positive values
    // that cannot be cancelled out within groups.
    // Actually, the minimum total debt equals the sum of absolute balances / 2? 
    // Let's think: we can rearrange arbitrarily as long as net balance per person stays same.
    // The minimum total debt = sum of positive balances = sum of absolute balances / 2.
    // Since total positive = total negative (sum balance = 0).

    // But careful: not all debts can be cancelled arbitrarily if there is no connection?
    // The problem says: simplify so that the difference remains same.
    // Actually, any person's net balance is fixed. We can create any debt edges as long as
    // for each person: incoming - outgoing = original net balance.
    // This is exactly a flow problem. The minimum sum of debts = sum of positive balances.
    // Because we can always connect each positive to a negative directly for the full amount.
    // Example 1: balances: 1: -10, 2: +8, 3: +1, 4: +1, 5: 0. Positives sum = 10. Output = 10.
    // Example 2: no debts, all balances 0, sum pos = 0. Output 0.
    // Example 3: 1->2 1, 2->3 1, 3->1 1 => balances all 0, sum pos = 0. Output 0.
    // So answer = sum of positive balances.

    long long ans = 0;
    for (int v : pos) ans += v;

    cout << ans << "\n";

    return 0;
}
